import{_ as t,o as e,c as s,ag as i}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"Call API","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/call.md","filePath":"zh/guide/call.md","lastUpdated":1776985505000}'),o={name:"zh/guide/call.md"};function r(l,a,d,n,h,p){return e(),s("div",null,[...a[0]||(a[0]=[i(`<h1 id="call-api" tabindex="-1">Call API <a class="header-anchor" href="#call-api" aria-label="Permalink to &quot;Call API&quot;">​</a></h1><p>EasyYapi 支持在 IDEA 中直接发起 API 请求，方便快速测试和调试。</p><h2 id="使用方法" tabindex="-1">使用方法 <a class="header-anchor" href="#使用方法" aria-label="Permalink to &quot;使用方法&quot;">​</a></h2><ol><li>打开项目中包含 API 的文件</li><li>点击 API 方法旁的行标记图标（▶），在 API Dashboard 中打开该端点</li><li>配置请求参数（主机、请求头、请求体等）</li><li>点击 <strong>Send</strong> 发起请求</li></ol><h2 id="配置" tabindex="-1">配置 <a class="header-anchor" href="#配置" aria-label="Permalink to &quot;配置&quot;">​</a></h2><h3 id="请求前回调" tabindex="-1">请求前回调 <a class="header-anchor" href="#请求前回调" aria-label="Permalink to &quot;请求前回调&quot;">​</a></h3><p>使用 <code>http.call.before</code> 在发送请求前执行自定义逻辑：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">http.call.before</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;&#39;&#39;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">it.header(&quot;Authorization&quot;, &quot;Bearer &quot; + localStorage.get(&quot;token&quot;))</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;&#39;&#39;</span></span></code></pre></div><h3 id="请求后回调" tabindex="-1">请求后回调 <a class="header-anchor" href="#请求后回调" aria-label="Permalink to &quot;请求后回调&quot;">​</a></h3><p>使用 <code>http.call.after</code> 在收到响应后执行自定义逻辑：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">http.call.after</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;&#39;&#39;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">if (it.response().code() == 200) {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    def body = it.response().body()</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    localStorage.set(&quot;token&quot;, body.token)</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;&#39;&#39;</span></span></code></pre></div><p>详见 <a href="/zh/settings/rules/http_call_before">http.call.before</a> 和 <a href="/zh/settings/rules/http_call_after">http.call.after</a>。</p><h2 id="grpc-调用" tabindex="-1">gRPC 调用 <a class="header-anchor" href="#grpc-调用" aria-label="Permalink to &quot;gRPC 调用&quot;">​</a></h2><p>EasyYapi 还支持直接从 IDE 调用 gRPC 方法。此功能默认禁用，需要在 IDE 设置中启用：</p><p><kbd>Settings</kbd> &gt; <kbd>Other Settings</kbd> &gt; <kbd>EasyApi</kbd> &gt; <kbd>gRPC</kbd></p><p>勾选 <strong>Enable gRPC call</strong> 复选框即可启用 gRPC 调用支持。</p><p>启用 gRPC 调用后，插件需要 gRPC 运行时 JAR 才能调用方法。可以通过以下方式配置运行时依赖：</p><ul><li><strong>IDE 设置</strong>：在 <kbd>Settings</kbd> &gt; <kbd>Other Settings</kbd> &gt; <kbd>EasyApi</kbd> &gt; gRPC Runtime 中使用 <strong>Auto Detect</strong> 按钮自动检测并解析依赖。</li></ul><p>详见 <a href="/zh/framework/grpc">gRPC 框架支持</a>。</p><h2 id="编辑器行标记导航" tabindex="-1">编辑器行标记导航 <a class="header-anchor" href="#编辑器行标记导航" aria-label="Permalink to &quot;编辑器行标记导航&quot;">​</a></h2><p>EasyYapi 会在编辑器中 API 方法旁添加行标记图标（▶）。点击该图标会打开 <strong>API Dashboard</strong> 并直接导航到对应的端点。</p><h3 id="支持的注解" tabindex="-1">支持的注解 <a class="header-anchor" href="#支持的注解" aria-label="Permalink to &quot;支持的注解&quot;">​</a></h3><p>行标记图标会出现在以下注解标注的方法上：</p><table tabindex="0"><thead><tr><th>框架</th><th>注解</th></tr></thead><tbody><tr><td>Spring MVC</td><td><code>@RequestMapping</code>、<code>@GetMapping</code>、<code>@PostMapping</code>、<code>@PutMapping</code>、<code>@DeleteMapping</code>、<code>@PatchMapping</code></td></tr><tr><td>JAX-RS</td><td><code>@GET</code>、<code>@POST</code>、<code>@PUT</code>、<code>@DELETE</code>、<code>@PATCH</code>、<code>@Path</code></td></tr><tr><td>gRPC</td><td>继承 <code>BindableService</code> 或标注 <code>@GrpcService</code> 的类中的 RPC 方法</td></tr></tbody></table><h3 id="自动重新扫描" tabindex="-1">自动重新扫描 <a class="header-anchor" href="#自动重新扫描" aria-label="Permalink to &quot;自动重新扫描&quot;">​</a></h3><p>如果当前索引中未找到端点（例如切换分支后或文件是新建的），点击行标记图标会自动触发对当前文件的重新扫描，然后导航到 Dashboard。</p><h2 id="api-dashboard" tabindex="-1">API Dashboard <a class="header-anchor" href="#api-dashboard" aria-label="Permalink to &quot;API Dashboard&quot;">​</a></h2><p>EasyYapi 提供了 <strong>API Dashboard</strong> 工具窗口，用于浏览、测试和管理 API 端点。可从 IDEA 底部工具窗口栏打开。</p><h3 id="浏览端点" tabindex="-1">浏览端点 <a class="header-anchor" href="#浏览端点" aria-label="Permalink to &quot;浏览端点&quot;">​</a></h3><p>Dashboard 以树形结构展示所有检测到的 API 端点，按模块和类组织：</p><ul><li><strong>颜色编码</strong>：HTTP 方法按颜色区分（GET=蓝色、POST=绿色、PUT=橙色、DELETE=红色、PATCH=青色），gRPC 端点显示为紫色，并带有流类型标识（<code>gRPC:U</code> 表示一元调用、<code>gRPC:S</code> 表示服务端流、<code>gRPC:C</code> 表示客户端流、<code>gRPC:B</code> 表示双向流）</li><li><strong>搜索</strong>：在搜索框中输入关键词，可按名称、路径、文件夹、描述或类名过滤端点（不区分大小写，带防抖输入）</li><li><strong>工具栏操作</strong>：刷新、导出、全部折叠、全部展开</li></ul><h3 id="端点详情" tabindex="-1">端点详情 <a class="header-anchor" href="#端点详情" aria-label="Permalink to &quot;端点详情&quot;">​</a></h3><p>在树中选择一个端点后，右侧会打开详情面板，包含：</p><ul><li><strong>请求行</strong>：HTTP 方法、主机 URL（带历史记录）、路径、发送和重置按钮</li><li><strong>标签页参数编辑器</strong>： <ul><li><strong>Path</strong> — 路径参数（如 <code>/users/{id}</code>）</li><li><strong>Params</strong> — 查询字符串和 Cookie 参数</li><li><strong>Headers</strong> — 请求头</li><li><strong>Form</strong> — 表单数据参数（用于 <code>application/x-www-form-urlencoded</code> 或 <code>multipart/form-data</code>）</li><li><strong>Body</strong> — JSON 请求体（带语法高亮）</li></ul></li><li><strong>响应面板</strong>：状态码、响应体（支持 Pretty/Raw JSON 切换和复制按钮）、响应头</li></ul><h3 id="发送请求" tabindex="-1">发送请求 <a class="header-anchor" href="#发送请求" aria-label="Permalink to &quot;发送请求&quot;">​</a></h3><ol><li>在树中选择一个端点</li><li>根据需要配置主机、参数、请求头和请求体</li><li>点击 <strong>Send</strong> 执行请求</li><li>在下方面板查看响应</li></ol><p>对于 gRPC 端点，Dashboard 会在发送前检查 gRPC 调用是否已启用以及运行时依赖是否可用。如果未配置，会提示你打开设置。</p><h3 id="右键菜单" tabindex="-1">右键菜单 <a class="header-anchor" href="#右键菜单" aria-label="Permalink to &quot;右键菜单&quot;">​</a></h3><p>在树中右键点击端点或文件夹可访问：</p><table tabindex="0"><thead><tr><th>操作</th><th>说明</th></tr></thead><tbody><tr><td><strong>Export</strong></td><td>将选中的端点导出为 Markdown、YApi、Postman、cURL 或 HttpClient</td></tr><tr><td><strong>Copy Path</strong></td><td>将端点路径复制到剪贴板</td></tr><tr><td><strong>Copy as cURL</strong></td><td>将端点的 cURL 命令复制到剪贴板</td></tr><tr><td><strong>Navigate to Source</strong></td><td>跳转到端点的源代码</td></tr><tr><td><strong>Reset to Default</strong></td><td>将用户修改重置为默认值</td></tr></tbody></table><p>双击端点可直接导航到其源代码。</p><h3 id="自动保存" tabindex="-1">自动保存 <a class="header-anchor" href="#自动保存" aria-label="Permalink to &quot;自动保存&quot;">​</a></h3><p>对请求参数、请求头、主机和请求体的用户修改会自动保存，当你再次访问同一端点时会自动恢复。</p>`,43)])])}const b=t(o,[["render",r]]);export{g as __pageData,b as default};
